export class QuestValidationError extends Error {
    code = 'INVALID_TASK_PARAMS';
    constructor(message: string) {
        super(message);
        this.name = 'QuestValidationError';
    }
}

export class QuestNotFoundError extends Error {
    code = 'NOT_FOUND';
