        this.name = 'QuestNotEditableError';
    }
}

export class QuestForbiddenError extends Error {
    code = 'FORBIDDEN';
    constructor() {
        super('You do not have permission to edit this quest');
        this.name = 'QuestForbiddenError';
    }
}

