     9→export async function discordRoutes(server: FastifyInstance) {
    10→
    11→  /** GET /discord/guild-info — resolve invite + check bot presence */
    12→  server.get(
    13→    '/guild-info',
    14→    {
    15→      schema: {
    16→        tags: ['Discord'],
    17→        summary: 'Resolve Discord invite and check bot presence',
    18→        querystring: z.object({ inviteCode: z.string().min(1) }),
    19→      },
    20→    },
    21→    async (request, reply) => {
    22→      if (!isDiscordConfigured()) {
    23→        return reply.status(503).send({ error: { message: 'Discord integration not configured', code: 'DISCORD_NOT_CONFIGURED' } })
    24→      }
    25→
    26→      const { inviteCode } = request.query as { inviteCode: string }
    27→      const info = await getGuildInfo(inviteCode)
    28→
    29→      if (!info) {
    30→        return reply.status(400).send({ error: { message: 'Invalid or expired Discord invite', code: 'INVALID_INVITE' } })
    31→      }
    32→
    33→      return { data: info }
    34→    },
    35→  )
    36→
    37→  /** GET /discord/guild-roles — fetch roles (requires auth, bot must be in server) */
    38→  server.get(
    39→    '/guild-roles',
    40→    {
    41→      schema: {
    42→        tags: ['Discord'],
    43→        summary: 'Fetch guild roles (bot must be in server)',
    44→        querystring: z.object({ guildId: z.string().regex(/^\d{17,20}$/, 'Invalid guild ID') }),
    45→      },
    46→      preHandler: [server.authenticate],
    47→    },
    48→    async (request, reply) => {
    49→      if (!isDiscordConfigured()) {
    50→        return reply.status(503).send({ error: { message: 'Discord integration not configured', code: 'DISCORD_NOT_CONFIGURED' } })
    51→      }
    52→
    53→      const { guildId } = request.query as { guildId: string }
    54→      const roles = await fetchGuildRoles(guildId)
    55→
    56→      if (!roles) {
    57→        return reply.status(403).send({ error: { message: 'Bot is not in this server. Invite the bot first.', code: 'BOT_NOT_IN_GUILD' } })
    58→      }
    59→
    60→      return { data: { roles } }
    61→    },
    62→  )
    63→
    64→  /** GET /discord/bot-invite-url — construct bot OAuth2 invite URL */
    65→  server.get(
    66→    '/bot-invite-url',
    67→    {
    68→      schema: {
    69→        tags: ['Discord'],
    70→        summary: 'Get bot invite URL',
    71→        querystring: z.object({ guildId: z.string().optional() }),
    72→      },
    73→    },
    74→    async (request, reply) => {
    75→      const clientId = process.env.DISCORD_CLIENT_ID
