     1→/**
     2→ * Lightweight Discord REST client — bare fetch(), no discord.js.
     3→ * Bot only needs guild membership read (permissions=0).
     4→ */
     5→
     6→const DISCORD_API = 'https://discord.com/api/v10'
     7→const TIMEOUT_MS = 8000
     8→
     9→export interface DiscordRole {
    10→  id: string       // snowflake
    11→  name: string
    12→  color: number    // integer color code
    13→  position: number // sort order (higher = more powerful)
    14→}
    15→
    16→interface DiscordInviteResponse {
    17→  guild?: { id: string; name: string }
    18→}
    19→
    20→interface DiscordRoleRaw {
    21→  id: string
    22→  name: string
    23→  color: number
    24→  position: number
    25→  managed: boolean
    26→}
    27→
    28→interface DiscordMemberResponse {
    29→  roles: string[]
    30→}
    31→
    32→function botHeaders(): Record<string, string> {
    33→  const token = process.env.DISCORD_BOT_TOKEN
    34→  if (!token) throw new Error('DISCORD_BOT_TOKEN not configured')
    35→  return {
    36→    'Authorization': `Bot ${token}`,
    37→    'User-Agent': 'DiscordBot (https://clawquest.ai, 1.0)',
    38→    'Content-Type': 'application/json',
    39→  }
    40→}
    41→
    42→/** Resolve invite code → guild info (public endpoint, no auth needed) */
    43→export async function resolveInvite(code: string): Promise<{ guildId: string; guildName: string } | null> {
    44→  try {
    45→    const res = await fetch(
    46→      `${DISCORD_API}/invites/${encodeURIComponent(code)}?with_counts=false`,
    47→      { signal: AbortSignal.timeout(TIMEOUT_MS) },
    48→    )
    49→    if (!res.ok) return null
    50→    const data = await res.json() as DiscordInviteResponse
    51→    if (!data.guild) return null
    52→    return { guildId: data.guild.id, guildName: data.guild.name }
    53→  } catch {
    54→    return null
    55→  }
    56→}
    57→
    58→/** Fetch all roles for a guild (bot must be a member). Returns sorted by position desc, excludes @everyone. */
    59→export async function getGuildRoles(guildId: string): Promise<DiscordRole[] | null> {
    60→  try {
    61→    const res = await fetch(
    62→      `${DISCORD_API}/guilds/${encodeURIComponent(guildId)}/roles`,
    63→      { headers: botHeaders(), signal: AbortSignal.timeout(TIMEOUT_MS) },
    64→    )
    65→    if (!res.ok) return null
    66→    const roles = await res.json() as DiscordRoleRaw[]
    67→    return roles
    68→      .filter(r => r.name !== '@everyone' && !r.managed)
    69→      .sort((a, b) => b.position - a.position)
    70→      .map(({ id, name, color, position }) => ({ id, name, color, position }))
    71→  } catch {
    72→    return null
    73→  }
    74→}
    75→
    76→/** Get a single member's role IDs in a guild. Returns role ID array or null. */
    77→export async function getGuildMember(guildId: string, userId: string): Promise<string[] | null> {
    78→  try {
    79→    const res = await fetch(
    80→      `${DISCORD_API}/guilds/${encodeURIComponent(guildId)}/members/${encodeURIComponent(userId)}`,
    81→      { headers: botHeaders(), signal: AbortSignal.timeout(TIMEOUT_MS) },
    82→    )
    83→    if (!res.ok) return null
    84→    const data = await res.json() as DiscordMemberResponse
    85→    return data.roles
    86→  } catch {
    87→    return null
    88→  }
    89→}
    90→
    91→/** Get member roles using the USER's own OAuth access token (guilds.members.read scope).
    92→ *  Does NOT require the bot to be in the server.
    93→ *  Discord endpoint: GET /users/@me/guilds/{guild.id}/member */
    94→export async function getUserGuildMember(accessToken: string, guildId: string): Promise<string[] | null> {
    95→  try {
    96→    const res = await fetch(
    97→      `${DISCORD_API}/users/@me/guilds/${encodeURIComponent(guildId)}/member`,
    98→      {
    99→        headers: {
   100→          'Authorization': `Bearer ${accessToken}`,
   101→          'User-Agent': 'DiscordBot (https://clawquest.ai, 1.0)',
   102→        },
   103→        signal: AbortSignal.timeout(TIMEOUT_MS),
   104→      },
   105→    )
   106→    if (!res.ok) return null
   107→    const data = await res.json() as DiscordMemberResponse
   108→    return data.roles
   109→  } catch {
   110→    return null
   111→  }
   112→}
   113→
   114→/** Check if Discord integration is configured (bot token + client ID) */
   115→export function isDiscordConfigured(): boolean {
   116→  return !!process.env.DISCORD_BOT_TOKEN && !!process.env.DISCORD_CLIENT_ID
   117→}
