    20→export class TelegramService {
    21→    public bot: Bot<BotContext>;
    22→
    23→    constructor(private server: FastifyInstance, token: string) {
    24→        this.bot = new Bot<BotContext>(token);
    25→
    26→        // Init Claude chat (graceful — logs warning if no API key)
    27→        const claudeReady = initClaudeChat();
    28→        if (claudeReady) {
    29→            server.log.info('Claude AI chat enabled for Telegram bot');
    30→        } else {
    31→            server.log.warn('ANTHROPIC_API_KEY not set — AI chat disabled, using FAQ fallback');
    32→        }
    33→
    34→        this.registerHandlers();
    35→    }
    36→
    37→    private registerHandlers() {
    38→        // Error boundary
    39→        this.bot.catch(errorMiddleware(this.server));
    40→
    41→        // Global middleware — logs ALL inbound messages before handlers
    42→        this.bot.use(chatLogMiddleware(this.server));
    43→
    44→        // Command handlers (order matters — specific before generic)
    45→        this.bot.use(startHandler(this.server));
    46→        this.bot.use(helpHandler(this.server));
    47→        this.bot.use(aboutHandler(this.server));
    48→        this.bot.use(statusHandler(this.server));
    49→        this.bot.use(verifyHandler(this.server));
    50→        this.bot.use(registerHandler(this.server));
    51→        this.bot.use(questsHandler(this.server));
    52→        this.bot.use(acceptHandler(this.server));
    53→        this.bot.use(doneHandler(this.server));
    54→        this.bot.use(createHandler(this.server));
    55→        this.bot.use(waitlistHandler(this.server));
    56→
    57→        // Fallback must be last — catches unmatched messages + active sessions
    58→        this.bot.use(fallbackHandler(this.server));
    59→    }
    60→
    61→    public async startPolling() {
    62→        // Ensure no webhook is set — otherwise Telegram sends updates only to webhook URL
    63→        // and getUpdates (polling) receives nothing. Common cause of "bot works in dev, not in prod".
    64→        try {
    65→            await this.bot.api.deleteWebhook({ drop_pending_updates: false });
    66→            this.server.log.info('Telegram bot: webhook cleared (using polling)');
    67→        } catch (err) {
    68→            this.server.log.warn({ err }, 'Telegram deleteWebhook failed (continuing with polling)');
    69→        }
    70→
    71→        // Register bot menu commands with Telegram
    72→        await this.bot.api.setMyCommands([
