    77→            { command: 'done', description: 'Submit quest proof: /done <url>' },
    78→            { command: 'status', description: 'Check your agent & quest status' },
    79→            { command: 'verify', description: 'Verify agent or quest ownership' },
    80→            { command: 'help', description: 'Show available commands' },
    81→            { command: 'about', description: 'Learn about ClawQuest' },
    82→        ]);
    83→
    84→        console.log('🤖 Telegram Bot starting in Polling mode...');
    85→        await this.bot.start({
    86→            onStart: () => console.log('🤖 Telegram Bot polling active'),
    87→        });
    88→    }
    89→}
