     3→/** Response type for social validation */
     4→export interface SocialValidationResult {
     5→  valid: boolean
     6→  error?: string
     7→  meta?: Record<string, string>
     8→}
     9→
    10→/** Optional user context for role-based verification at quest completion */
    11→export interface ValidationContext {
    12→  discordId?: string | null
    13→  discordAccessToken?: string | null   // OAuth2 token with guilds.members.read scope
    14→  params?: Record<string, string>
    15→}
    16→
    17→const TIMEOUT_MS = 8000
    18→
    19→/** Validate X (Twitter) account existence via oEmbed */
    20→async function validateXAccount(username: string): Promise<SocialValidationResult> {
    21→  const handle = username.replace(/^@/, '')
    22→  try {
    23→    const res = await fetch(
    24→      `https://publish.twitter.com/oembed?url=https://x.com/${handle}`,
    25→      { signal: AbortSignal.timeout(TIMEOUT_MS) },
    26→    )
    27→    if (res.ok) {
    28→      const data = await res.json() as { author_name?: string }
    29→      return { valid: true, meta: { name: data.author_name ?? handle } }
    30→    }
    31→    if (res.status === 404) return { valid: false, error: 'X account not found' }
    32→    return { valid: false, error: 'X account not found' }
    33→  } catch {
    34→    return { valid: true }
    35→  }
    36→}
    37→
    38→/** Validate X (Twitter) post existence via oEmbed */
    39→async function validateXPost(postUrl: string): Promise<SocialValidationResult> {
    40→  try {
    41→    const res = await fetch(
    42→      `https://publish.twitter.com/oembed?url=${encodeURIComponent(postUrl)}`,
    43→      { signal: AbortSignal.timeout(TIMEOUT_MS) },
    44→    )
    45→    if (res.ok) {
    46→      const data = await res.json() as { author_name?: string }
    47→      return { valid: true, meta: { author: data.author_name ?? '' } }
    48→    }
    49→    return { valid: false, error: 'Post not found or is private' }
    50→  } catch {
    51→    return { valid: true }
    52→  }
    53→}
    54→
    55→/** Extract Discord invite code from URL or raw code */
    56→function extractDiscordCode(value: string): string | null {
    57→  const urlMatch = value.match(/discord\.(?:gg|com\/invite)\/([A-Za-z0-9-]+)/)
    58→  if (urlMatch) return urlMatch[1]
    59→  // Treat bare alphanumeric string as code
    60→  if (/^[A-Za-z0-9-]+$/.test(value.trim())) return value.trim()
    61→  return null
    62→}
    63→
    64→/** Validate Discord invite via Discord API */
    65→async function validateDiscordInvite(value: string): Promise<SocialValidationResult> {
    66→  const code = extractDiscordCode(value)
    67→  if (!code) return { valid: false, error: 'Discord invite is invalid or expired' }
    68→  try {
    69→    const res = await fetch(
    70→      `https://discord.com/api/v10/invites/${code}?with_counts=true`,
    71→      { signal: AbortSignal.timeout(TIMEOUT_MS) },
    72→    )
    73→    if (res.ok) {
    74→      const data = await res.json() as { guild?: { name?: string } }
    75→      return { valid: true, meta: { name: data.guild?.name ?? '' } }
    76→    }
    77→    return { valid: false, error: 'Discord invite is invalid or expired' }
    78→  } catch {
    79→    return { valid: true }
    80→  }
    81→}
    82→
    83→/** Extract Telegram channel username from @handle or t.me URL */
    84→function extractTelegramUsername(value: string): string | null {
    85→  if (value.startsWith('@')) return value.slice(1)
    86→  const urlMatch = value.match(/t\.me\/([A-Za-z0-9_]+)/)
    87→  if (urlMatch) return urlMatch[1]
    88→  if (/^[A-Za-z0-9_]+$/.test(value.trim())) return value.trim()
    89→  return null
    90→}
    91→
    92→/** Validate Telegram channel existence via Bot API getChat */
    93→async function validateTelegramChannel(
    94→  value: string,
    95→  botToken: string | undefined,
    96→): Promise<SocialValidationResult> {
    97→  if (!botToken) {
    98→    return { valid: true, meta: { warning: 'Telegram validation unavailable' } }
    99→  }
   100→  const username = extractTelegramUsername(value)
   101→  if (!username) return { valid: false, error: 'Channel not found or is private' }
   102→  try {
   103→    const res = await fetch(
   104→      `https://api.telegram.org/bot${botToken}/getChat?chat_id=@${username}`,
   105→      { signal: AbortSignal.timeout(TIMEOUT_MS) },
   106→    )
   107→    if (res.ok) {
   108→      const data = await res.json() as { ok?: boolean; result?: { title?: string } }
   109→      if (data.ok) {
   110→        return { valid: true, meta: { title: data.result?.title ?? username } }
   111→      }
   112→    }
   113→    return { valid: false, error: 'Channel not found or is private' }
   114→  } catch {
   115→    return { valid: true }
   116→  }
   117→}
   118→
   119→/** Verify participant holds a specific Discord role.
   120→ *  Prefers OAuth user token (guilds.members.read) over bot — no bot-in-server required. */
   121→async function validateDiscordRole(
   122→  params: Record<string, string>,
   123→  discordId: string | null | undefined,
   124→  discordAccessToken?: string | null,
   125→): Promise<SocialValidationResult> {
   126→  if (!discordId) {
   127→    return { valid: false, error: 'Link your Discord account to verify role' }
   128→  }
   129→  const { guildId, roleId, roleName } = params
   130→  if (!guildId || !roleId) {
   131→    return { valid: false, error: 'Quest task missing guild/role data' }
   132→  }
   133→
   134→  // Prefer OAuth user token (no bot in server required)
   135→  let memberRoles: string[] | null = null
   136→  if (discordAccessToken) {
   137→    memberRoles = await getUserGuildMember(discordAccessToken, guildId)
   138→  }
   139→  // Fallback to bot if no OAuth token or token failed
   140→  if (!memberRoles) {
   141→    memberRoles = await getGuildMember(guildId, discordId)
   142→  }
   143→
   144→  if (!memberRoles) {
   145→    return { valid: false, error: 'Not a member of the Discord server (or bot not in server)' }
   146→  }
   147→  if (!memberRoles.includes(roleId)) {
   148→    return { valid: false, error: `Missing required role: ${roleName || 'unknown'}` }
   149→  }
   150→  return { valid: true, meta: { roleName: roleName || roleId } }
   151→}
   152→
   153→/** Main dispatcher — routes to per-platform validators */
   154→export async function validateSocialTarget(
   155→  platform: string,
   156→  type: string,
   157→  value: string,
   158→  telegramBotToken?: string,
   159→  context?: ValidationContext,
   160→): Promise<SocialValidationResult> {
   161→  switch (platform) {
   162→    case 'x': {
   163→      if (type === 'follow_account') return validateXAccount(value)
   164→      if (['like_post', 'repost', 'quote_post'].includes(type)) return validateXPost(value)
   165→      // post = user creates new content, skip validation
   166→      return { valid: true }
   167→    }
   168→    case 'discord': {
   169→      if (type === 'verify_role' && context?.discordId !== undefined) {
   170→        // Completion-time: check if user actually has the role
   171→        return validateDiscordRole(context.params ?? {}, context.discordId, context.discordAccessToken)
   172→      }
   173→      if (['join_server', 'verify_role'].includes(type)) return validateDiscordInvite(value)
   174→      return { valid: true }
   175→    }
   176→    case 'telegram': {
   177→      if (type === 'join_channel') return validateTelegramChannel(value, telegramBotToken)
   178→      return { valid: true }
   179→    }
   180→    default:
   181→      return { valid: true }
   182→  }
   183→}
