    34→
    35→// ── X Verification ──────────────────────────────────────────────
    36→
    37→async function verifyXAction(
    38→  actionType: string, ctx: VerificationContext, taskIndex: number,
    39→): Promise<SocialValidationResult> {
    40→  // Support multiple param key conventions used by quest creators
    41→  const targetValue = ctx.params?.targetUrl || ctx.params?.postUrl || ctx.params?.accountHandle || ctx.params?.username || ''
    42→
    43→  switch (actionType) {
    44→    case 'post':
    45→    case 'quote_post': {
    46→      const proofUrl = ctx.proofUrls?.[taskIndex]
    47→      if (!proofUrl) return { valid: false, error: 'Paste your tweet URL to verify' }
    48→      const proofTweetId = extractTweetId(proofUrl)
    49→      if (!proofTweetId) return { valid: false, error: 'Invalid tweet URL — use format: https://x.com/.../status/...' }
    50→
    51→      // Path A: OAuth (most authoritative)
    52→      if (ctx.xId) {
    53→        const token = await ensureFreshToken(
    54→          { id: ctx.userId, xAccessToken: ctx.xAccessToken, xRefreshToken: ctx.xRefreshToken, xTokenExpiry: ctx.xTokenExpiry },
    55→          ctx.prisma,
    56→        )
    57→        if (token) {
    58→          const tweet = await getTweet(token, proofTweetId)
    59→          if (!tweet) return { valid: false, error: 'Tweet not found — is it public?' }
    60→          if (tweet.authorId !== ctx.xId) return { valid: false, error: 'This tweet was not posted by your linked X account' }
    61→          if (actionType === 'quote_post') {
    62→            const targetTweetId = extractTweetId(targetValue)
    63→            if (targetTweetId && tweet.quotedTweetId !== targetTweetId) {
    64→              return { valid: false, error: 'This tweet does not quote the required post' }
    65→            }
    66→          }
    67→          return { valid: true }
    68→        }
    69→      }
    70→
    71→      // Path B: RapidAPI fallback
    72→      const rapidApiKey = process.env.RAPID_API_KEY
    73→      if (rapidApiKey) {
    74→        if (actionType === 'quote_post') {
    75→          const result = await fetchTweetForQuoteVerify(proofTweetId, rapidApiKey)
    76→          if (!result) return { valid: false, error: 'Tweet not found — is it public?' }
    77→          if (ctx.xId && result.authorId && result.authorId !== ctx.xId) {
    78→            return { valid: false, error: 'This tweet was not posted by your linked X account' }
    79→          }
    80→          const targetTweetId = extractTweetId(targetValue)
    81→          if (targetTweetId && result.quotedStatusId !== targetTweetId) {
    82→            return { valid: false, error: 'This tweet does not quote the required post' }
    83→          }
    84→          return { valid: true }
    85→        }
    86→        const tweet = await fetchTweetById(proofTweetId, rapidApiKey)
    87→        if (!tweet) return { valid: false, error: 'Tweet not found — is it public?' }
    88→        if (ctx.xHandle) {
    89→          if (normaliseHandle(tweet.author.screenName) !== normaliseHandle(ctx.xHandle)) {
    90→            return { valid: false, error: 'This tweet was not posted by your linked X account' }
    91→          }
    92→        } else if (ctx.xId && tweet.author.id && tweet.author.id !== ctx.xId) {
    93→          return { valid: false, error: 'This tweet was not posted by your linked X account' }
    94→        }
    95→        return { valid: true }
    96→      }
    97→
    98→      return { valid: false, error: 'Link your X account to verify this task' }
    99→    }
   100→    case 'follow_account': {
   101→      const targetHandle = targetValue.replace(/^@/, '').replace(/^https?:\/\/(x|twitter)\.com\//, '')
   102→
   103→      // Prefer OAuth path when user has linked X (official API); fallback to RapidAPI when no token
   104→      if (ctx.xId && (ctx.xAccessToken || ctx.xRefreshToken)) {
   105→        const token = await ensureFreshToken(
   106→          { id: ctx.userId, xAccessToken: ctx.xAccessToken, xRefreshToken: ctx.xRefreshToken, xTokenExpiry: ctx.xTokenExpiry },
   107→          ctx.prisma,
   108→        )
   109→        if (!token) {
   110→          // Token refresh failed - expired
   111→          return { valid: false, error: 'X account token expired — please re-link your X account' }
   112→        }
   113→        const targetXId = await lookupUserByUsername(token, targetHandle)
   114→        if (targetXId) {
   115→          const follows = await checkFollowing(token, ctx.xId, targetXId)
   116→          if (follows !== null) return follows ? { valid: true } : { valid: false, error: 'not following this account' }
   117→        }
   118→      }
   119→      // Fallback: RapidAPI (no OAuth). Requires xHandle.
   120→      if (!ctx.xHandle) return { valid: false, error: 'Link your X account to verify this task' }
   121→      const follows = await checkUserFollows(ctx.xHandle, targetHandle)
   122→      if (follows === null) return { valid: false, error: 'Follow verification unavailable — try again later' }
   123→      return follows ? { valid: true } : { valid: false, error: 'not following this account' }
   124→    }
   125→    case 'like_post': {
   126→      if (!ctx.xId) return { valid: false, error: 'Link your X account to verify this task' }
   127→      const tweetId = extractTweetId(targetValue) || targetValue
   128→      if (!tweetId) return { valid: false, error: 'Quest task missing tweet URL — contact quest creator' }
   129→      // Primary: X API v2 app-only bearer token
   130→      const liked = await checkUserLikedTweet(ctx.xId, tweetId)
   131→      if (liked !== null) return liked ? { valid: true } : { valid: false, error: 'You have not liked this tweet' }
   132→      // Fallback: RapidAPI (uses xHandle)
   133→      if (!ctx.xHandle) return { valid: false, error: 'Like verification unavailable — try again later' }
   134→      const likedRapid = await checkUserLikedTweetRapid(tweetId, ctx.xId)
   135→      if (likedRapid === null) return { valid: false, error: 'Like verification unavailable — try again later' }
   136→      return likedRapid ? { valid: true } : { valid: false, error: 'You have not liked this tweet' }
   137→    }
   138→    case 'repost': {
   139→      if (!ctx.xId) return { valid: false, error: 'Link your X account to verify this task' }
   140→      const tweetId = extractTweetId(targetValue) || targetValue
   141→      if (!tweetId) return { valid: false, error: 'Quest task missing tweet URL — contact quest creator' }
   142→      // Primary: X API v2 app-only bearer token
   143→      const bearerToken = getAppBearerToken()
   144→      if (bearerToken) {
   145→        const retweeted = await getRetweetedBy(bearerToken, tweetId, ctx.xId)
   146→        if (retweeted !== null) return retweeted ? { valid: true } : { valid: false, error: 'You have not reposted this tweet' }
   147→      }
   148→      // Fallback: RapidAPI (uses xHandle)
   149→      if (!ctx.xHandle) return { valid: false, error: 'Repost verification unavailable — try again later' }
   150→      const retweetedRapid = await checkUserRetweeted(tweetId, ctx.xHandle)
   151→      if (retweetedRapid === null) return { valid: false, error: 'Repost verification unavailable — try again later' }
   152→      return retweetedRapid ? { valid: true } : { valid: false, error: 'You have not reposted this tweet' }
   153→    }
   154→    default:
   155→      return { valid: true }
   156→  }
   157→}
