   159→// ── Discord Verification ────────────────────────────────────────
   160→
   161→async function verifyDiscordAction(
   162→  actionType: string, ctx: VerificationContext,
   163→): Promise<SocialValidationResult> {
   164→  if (!ctx.discordId) return { valid: false, error: 'Link your Discord account to verify this task' }
   165→
   166→  if (actionType === 'join_server') {
   167→    let guildId = ctx.params?.guildId
   168→    // Fallback: resolve inviteUrl → guildId (handles legacy quests or when createQuest/updateQuest did not resolve)
   169→    if (!guildId && ctx.params?.inviteUrl) {
   170→      const code = ctx.params.inviteUrl.replace(/^https?:\/\/(discord\.gg|discord\.com\/invite)\//i, '').trim()
   171→      if (code) {
   172→        const guild = await resolveInvite(code)
   173→        if (guild) guildId = guild.guildId
   174→      }
   175→    }
   176→    if (!guildId) return { valid: false, error: 'Quest task missing guildId — contact quest creator' }
   177→
   178→    // Prefer OAuth user token (no bot needed)
   179→    if (ctx.discordAccessToken) {
   180→      const roles = await getUserGuildMember(ctx.discordAccessToken, guildId)
   181→      if (roles !== null) return { valid: true }
   182→    }
   183→    // Fallback to bot
   184→    const botRoles = await getGuildMember(guildId, ctx.discordId)
   185→    if (botRoles !== null) return { valid: true }
   186→
   187→    return { valid: false, error: 'You have not joined this Discord server' }
   188→  }
   189→
   190→  // verify_role: delegate to existing validateDiscordRole via validateSocialTarget
   191→  if (actionType === 'verify_role') {
   192→    return validateSocialTarget('discord', 'verify_role', '', undefined, {
   193→      discordId: ctx.discordId,
   194→      discordAccessToken: ctx.discordAccessToken,
   195→      params: ctx.params,
   196→    })
   197→  }
   198→
   199→  return { valid: true }
   200→}
   201→
   202→// ── Telegram Verification ───────────────────────────────────────
   203→
   204→async function verifyTelegramAction(
   205→  actionType: string, ctx: VerificationContext,
   206→): Promise<SocialValidationResult> {
   207→  if (actionType !== 'join_channel') return { valid: true }
   208→  if (!ctx.telegramId) return { valid: false, error: 'Link your Telegram account to verify this task' }
   209→  if (!ctx.telegramBotToken) return { valid: false, error: 'Telegram verification unavailable' }
   210→
   211→  const channelUrl = ctx.params?.channelUrl || ctx.params?.targetUrl || ''
   212→  let chatId: string
   213→  const urlMatch = channelUrl.match(/t\.me\/([A-Za-z0-9_]+)/)
   214→  if (urlMatch) chatId = `@${urlMatch[1]}`
   215→  else if (channelUrl.startsWith('@')) chatId = channelUrl
   216→  else chatId = `@${channelUrl.replace(/^https?:\/\//, '')}`
   217→
   218→  try {
   219→    const res = await fetch(
   220→      `https://api.telegram.org/bot${ctx.telegramBotToken}/getChatMember?chat_id=${encodeURIComponent(chatId)}&user_id=${ctx.telegramId}`,
   221→      { signal: AbortSignal.timeout(8000) },
   222→    )
   223→
   224→    // Always parse body — Telegram always returns JSON even for HTTP errors
   225→    const data = await res.json() as { ok: boolean; result?: { status: string }; description?: string; error_code?: number }
   226→
   227→    if (!data.ok) {
   228→      const desc = data.description ?? ''
   229→      console.error(`[Telegram] getChatMember failed for chatId=${chatId} userId=${ctx.telegramId}: ${res.status} ${desc}`)
   230→
   231→      if (desc.includes('CHAT_ADMIN_REQUIRED') || res.status === 403)
   232→        return { valid: false, error: 'Bot must be added as an admin of this channel' }
   233→      if (desc.includes('chat not found'))
   234→        return { valid: false, error: 'Channel not found — verify the channel URL in the quest task' }
   235→      if (desc.includes('USER_ID_INVALID') || desc.includes('user not found'))
   236→        return { valid: false, error: 'Could not verify your Telegram account — try unlinking and relinking' }
   237→
   238→      return { valid: false, error: `Telegram error: ${desc || 'Could not check membership'}` }
   239→    }
   240→
   241→    const joined = ['creator', 'administrator', 'member', 'restricted'].includes(data.result?.status ?? '')
   242→    return joined
   243→      ? { valid: true }
   244→      : { valid: false, error: 'You have not joined this channel' }
   245→  } catch {
   246→    return { valid: false, error: 'Telegram API unavailable — try again later' }
   247→  }
   248→}
   249→
   250→// ── Main Dispatcher ─────────────────────────────────────────────
   251→
   252→/** Completion-time verification: did user actually perform this action? */
   253→export async function verifySocialAction(
   254→  platform: string, actionType: string, taskIndex: number, ctx: VerificationContext,
   255→): Promise<SocialValidationResult> {
   256→  switch (platform) {
   257→    case 'x': return verifyXAction(actionType, ctx, taskIndex)
   258→    case 'discord': return verifyDiscordAction(actionType, ctx)
   259→    case 'telegram': return verifyTelegramAction(actionType, ctx)
   260→    default: return { valid: true }
   261→  }
   262→}
